#include <bits/stdc++.h>
using namespace std;

const int N=2e5+5;

struct Node{
    int id,val;
}a[N],b[N],c[N];

bool cmp(Node x,Node y){
    return x.val>y.val;
}

int n,x[N],y[N],z[N];
bool del[N];

int main(){
    scanf("%d",&n);
    for(int i=1;i<=n;i++){
        scanf("%d%d%d",&a[i].val,&b[i].val,&c[i].val);
        a[i].id=b[i].id=c[i].id=i;
        x[i]=a[i].val,y[i]=b[i].val,z[i]=c[i].val;
    }
    sort(a+1,a+n+1,cmp);
    sort(b+1,b+n+1,cmp);
    sort(c+1,c+n+1,cmp);
    for(int i=1,j=1,k=1;;){
        while(i<=n && del[a[i].id])
            i++;
        while(j<=n && del[b[j].id])
            j++;
        while(k<=n && del[c[k].id])
            k++;
        if(i>n || j>n || k>n)
            break;
        while(j<=n && a[i].val<=x[b[j].id])
            del[b[j].id]=1,j++;
        while(k<=n && a[i].val<=x[c[k].id])
            del[c[k].id]=1,k++;
        if(j>n || k>n)
            break;
        while(i<=n && b[j].val<=y[a[i].id])
            del[a[i].id]=1,i++;
        while(k<=n && b[j].val<=y[c[k].id])
            del[c[k].id]=1,k++;
        if(i>n || k>n)
            break;
        while(i<=n && c[k].val<=z[a[i].id])
            del[a[i].id]=1,i++;
        while(j<=n && c[k].val<=z[b[j].id])
            del[b[j].id]=1,j++;
        if(i>n || j>n)
            break;
        if(del[a[i].id] || del[b[j].id] || del[c[k].id])
            continue;
        if(a[i].val<=x[b[j].id] || a[i].val<=x[c[k].id])
            continue;
        if(b[j].val<=y[a[i].id] || b[j].val<=y[c[k].id])
            continue;
        if(c[k].val<=z[a[i].id] || c[k].val<=z[b[j].id])
            continue;
        printf("%d",a[i].val+b[j].val+c[k].val);
        return 0;
    }
    printf("-1");
    return 0;
}
